export const Controls: React.FC = () => {
  const { status, settings, obsAutoConfig, setObsAutoConfig, isBackendOffline } = useApp();
  const [isLoading, setIsLoading] = useState(false);

  const handleStart = async () => {
    setIsLoading(true);
    try {
      await api.startStream(settings, obsAutoConfig);
    } catch (error) {
      console.error("Failed to start stream", error);
      alert("Failed to start stream. Check backend connection.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleStop = async () => {
    setIsLoading(true);
    try {
      await api.stopStream();
    } catch (error) {
      console.error("Failed to stop stream", error);
    } finally {
      setIsLoading(false);
    }
  };

  const isStreaming = status.streaming;
  const canStart = !isBackendOffline && status.device.androidConnected && !isStreaming;
  const canStop = !isBackendOffline && isStreaming;

  return (
    <div className="bg-surface rounded-xl p-6 border border-surfaceHighlight shadow-lg flex flex-col justify-between h-full">
      <div>
        <h2 className="text-lg font-semibold text-white mb-6 flex items-center gap-2">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-textSecondary" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
          Stream Controls
        </h2>

        <div className="grid grid-cols-2 gap-4 mb-6">
          <button
            onClick={handleStart}
            disabled={!canStart || isLoading}
            className={`flex flex-col items-center justify-center p-6 rounded-xl border transition-all duration-200 ${
              canStart 
                ? 'bg-gradient-to-br from-indigo-500 to-primary border-transparent hover:shadow-lg hover:shadow-primary/25 text-white' 
                : 'bg-surfaceHighlight/30 border-surfaceHighlight text-textSecondary cursor-not-allowed opacity-50'
            }`}
          >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
             </svg>
             <span className="font-bold text-lg">Start Streaming</span>
          </button>

          <button
            onClick={handleStop}
            disabled={!canStop || isLoading}
            className={`flex flex-col items-center justify-center p-6 rounded-xl border transition-all duration-200 ${
              canStop 
                ? 'bg-gradient-to-br from-red-500 to-red-600 border-transparent hover:shadow-lg hover:shadow-red-500/25 text-white' 
                : 'bg-surfaceHighlight/30 border-surfaceHighlight text-textSecondary cursor-not-allowed opacity-50'
            }`}
          >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 10a1 1 0 011-1h4a1 1 0 011 1v4a1 1 0 01-1 1h-4a1 1 0 01-1-1v-4z" />
             </svg>
             <span className="font-bold text-lg">Stop Streaming</span>
          </button>
        </div>
      </div>

      <div className="bg-surfaceHighlight/30 rounded-lg p-4 flex items-center justify-between">
        <div>
          <p className="text-sm font-medium text-white">Auto-configure OBS</p>
          <p className="text-xs text-textSecondary mt-1">Automatically adds video & audio sources</p>
        </div>

