export const LogViewer: React.FC = () => {
  const { logs } = useApp();
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  // Mock logs if empty for UI demo purposes
  const displayLogs = logs.length > 0 ? logs : [
    { id: '0', timestamp: new Date().toLocaleTimeString(), level: 'info', message: 'Waiting for connection...' },
  ];

  const getLevelColor = (level: string) => {
    switch (level) {
      case 'error': return 'text-red-400';
      case 'warning': return 'text-amber-400';
      case 'success': return 'text-emerald-400';
      default: return 'text-slate-300';
    }
  };

  return (
    <div className="bg-surface rounded-xl border border-surfaceHighlight shadow-lg flex flex-col h-full overflow-hidden">
      <div className="p-3 border-b border-surfaceHighlight bg-surfaceHighlight/20 flex justify-between items-center">
        <span className="text-xs font-mono text-textSecondary uppercase tracking-wide">System Logs</span>
        <div className="flex gap-1.5">
          <div className="w-2.5 h-2.5 rounded-full bg-red-500/20"></div>
          <div className="w-2.5 h-2.5 rounded-full bg-amber-500/20"></div>
          <div className="w-2.5 h-2.5 rounded-full bg-emerald-500/20"></div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 font-mono text-xs custom-scrollbar bg-[#0b1120]">
        {displayLogs.map((log, idx) => (
          <div key={log.id || idx} className="mb-1 last:mb-0 break-words leading-relaxed">
            <span className="text-slate-500 mr-3">[{log.timestamp}]</span>
            <span className={getLevelColor(log.level)}>{log.message}</span>
          </div>
        ))}
        <div ref={bottomRef} />
