import { app, BrowserWindow, ipcMain, shell } from 'electron';
import path from 'path';
import { fileURLToPath } from 'url';

// Fix for __dirname in ESM context
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

let mainWindow: BrowserWindow | null = null;

function createWindow() {
  mainWindow = new BrowserWindow({
    width: 1000,
    height: 800,
    minWidth: 800,
    minHeight: 600,
    title: 'Stremfusion',
    backgroundColor: '#0f172a', // Slate-900 matches the UI theme
    webPreferences: {
      nodeIntegration: false,
      contextIsolation: true,
      preload: path.join(__dirname, 'preload.js'),
    },
    frame: true, // Use system frame or set to false for custom header
  });

  // In development, load from the dev server (e.g., Vite default port 5173)
  // In production, load the built index.html
  const isDev = process.env.NODE_ENV === 'development';
  if (isDev) {
    mainWindow.loadURL('http://localhost:5173');
    mainWindow.webContents.openDevTools();
  } else {
    mainWindow.loadFile(path.join(__dirname, '../dist/index.html'));
  }

  // Handle external links
  mainWindow.webContents.setWindowOpenHandler(({ url }) => {
    shell.openExternal(url);
    return { action: 'deny' };
  });

  mainWindow.on('closed', () => {
    mainWindow = null;
  });
}

app.whenReady().then(createWindow);

app.on('window-all-closed', () => {
  if ((process as any).platform !== 'darwin') {
    app.quit();
  }
});

app.on('activate', () => {
  if (mainWindow === null) {
    createWindow();
  }
});

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { AppSettings, BackendStatus, LogEntry } from '../types';
import { api } from '../services/api';

interface AppContextType {
  settings: AppSettings;
  updateSettings: (newSettings: Partial<AppSettings>) => void;
  status: BackendStatus;
  logs: LogEntry[];
  isSettingsOpen: boolean;
  setIsSettingsOpen: (open: boolean) => void;
  refreshStatus: () => Promise<void>;
  isBackendOffline: boolean;
  obsAutoConfig: boolean;
  setObsAutoConfig: (val: boolean) => void;
}

const defaultSettings: AppSettings = {
  scrcpyResolution: 1080,
  scrcpyBitrate: 8,
  scrcpyFps: 60,
  obsHost: 'localhost',
  obsPort: 4455,
  obsPassword: '',
};

const defaultStatus: BackendStatus = {
  isOnline: false,
  streaming: false,
  device: {
    androidConnected: false,
    iosConnected: false,
    usbDebugging: false,
  },
  obs: {
    connected: false,
    sources: { screen: false, audio: false },
  },
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [settings, setSettings] = useState<AppSettings>(() => {
    const saved = localStorage.getItem('stremfusion_settings');
    return saved ? JSON.parse(saved) : defaultSettings;
  });

  const [status, setStatus] = useState<BackendStatus>(defaultStatus);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [obsAutoConfig, setObsAutoConfig] = useState(true);
  const [isBackendOffline, setIsBackendOffline] = useState(true);

  const updateSettings = (newSettings: Partial<AppSettings>) => {
    const updated = { ...settings, ...newSettings };
    setSettings(updated);
    localStorage.setItem('stremfusion_settings', JSON.stringify(updated));
  };

  const refreshStatus = async () => {
    try {
      const res = await api.getStatus();
      setStatus({ ...res.data, isOnline: true });
      setIsBackendOffline(false);
    } catch (err) {
      setIsBackendOffline(true);
      setStatus((prev) => ({ ...prev, isOnline: false }));
    }
  };

  const fetchLogs = async () => {
    try {
      const res = await api.getLogs();
      if (res.data && Array.isArray(res.data)) {
        // Assuming backend returns all logs or recent ones. 
        // We'll just replace for simplicity or append based on IDs in a real app.
        setLogs(res.data);
      }
    } catch (err) {
      // SIlent fail for logs
    }
  };

  useEffect(() => {
    // Initial fetch
    refreshStatus();

    // Polling interval
    const interval = setInterval(() => {
      refreshStatus();
      if (!isBackendOffline) {
        fetchLogs();
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [isBackendOffline]);

  return (
    <AppContext.Provider
      value={{
        settings,
        updateSettings,
        status,
        logs,
        isSettingsOpen,
        setIsSettingsOpen,
        refreshStatus,
        isBackendOffline,
        obsAutoConfig,
        setObsAutoConfig
      }}
    >
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

