import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { AppSettings, BackendStatus, LogEntry, ViewType } from '../types';
import { api } from '../services/api';

interface AppContextType {
  settings: AppSettings;
  updateSettings: (newSettings: Partial<AppSettings>) => void;
  status: BackendStatus;
  logs: LogEntry[];
  currentView: ViewType;
  setCurrentView: (view: ViewType) => void;
  isTutorialOpen: boolean;
  setIsTutorialOpen: (open: boolean) => void;
  isSettingsOpen: boolean;
  setIsSettingsOpen: (open: boolean) => void;
  isAboutOpen: boolean;
  setIsAboutOpen: (open: boolean) => void;
  refreshStatus: () => Promise<void>;
  isBackendOffline: boolean;
  obsAutoConfig: boolean;
  setObsAutoConfig: (val: boolean) => void;
}

const defaultSettings: AppSettings = {
  scrcpyResolution: 1080,
  scrcpyBitrate: 8,
  scrcpyFps: 60,
  obsHost: 'localhost',
  obsPort: 4455,
  obsPassword: '',
  theme: 'dark',
};

const defaultStatus: BackendStatus = {
  isOnline: false,
  streaming: false,
  device: {
    androidConnected: false,
    iosConnected: false,
    usbDebugging: false,
    currentDevice: undefined,
  },
  obs: {
    connected: false,
    sources: { screen: false, audio: false },
  },
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [settings, setSettings] = useState<AppSettings>(() => {
    const saved = localStorage.getItem('stremfusion_settings');
    return saved ? JSON.parse(saved) : defaultSettings;
  });

  const [status, setStatus] = useState<BackendStatus>(defaultStatus);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [currentView, setCurrentView] = useState<ViewType>('connection');
  const [isTutorialOpen, setIsTutorialOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isAboutOpen, setIsAboutOpen] = useState(false);
  const [obsAutoConfig, setObsAutoConfig] = useState(true);
  const [isBackendOffline, setIsBackendOffline] = useState(true);

  const refreshStatus = async () => {
    try {
      const res = await api.getStatus();
      setStatus({ ...res.data, isOnline: true });
      setIsBackendOffline(false);

      const logRes = await api.getLogs();
      if (logRes.data) setLogs(logRes.data);
    } catch (err) {
      setIsBackendOffline(true);
      setStatus((prev) => ({ 
        ...prev, 
        isOnline: false,
        device: { ...prev.device, androidConnected: false, currentDevice: undefined },
        obs: { ...prev.obs, connected: false }
      }));
    }
  };

  const updateSettings = (newSettings: Partial<AppSettings>) => {
    const updated = { ...settings, ...newSettings };
    setSettings(updated);
    localStorage.setItem('stremfusion_settings', JSON.stringify(updated));
  };

  useEffect(() => {
    refreshStatus();
    const interval = setInterval(refreshStatus, 3000);
    return () => clearInterval(interval);
  }, []);

  return (
    <AppContext.Provider
      value={{
        settings,
        updateSettings,
        status,
        logs,
        currentView,
        setCurrentView,
        isTutorialOpen,
        setIsTutorialOpen,
        isSettingsOpen,
        setIsSettingsOpen,
        isAboutOpen,
        setIsAboutOpen,
        refreshStatus,
        isBackendOffline,
        obsAutoConfig,
        setObsAutoConfig
      }}
    >
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

